    """
    Check if the given integer is a prime number.

    :param n: Integer to check
    :return: Boolean indicating if n is prime
    """
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n ** 0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

