def first_Digit(n: int) -> int:
    """
    Returns the first digit of n! (factorial of n).
    """
    if n < 0:
        raise ValueError("Input must be a non-negative integer")
    if n == 0 or n == 1:
        return 1

    import math
    log_sum = 0.0
    for i in range(2, n + 1):
        log_sum += math.log10(i)

    # The fractional part of log10(n!) gives the leading digits
    fractional_part = log_sum - int(log_sum)
    leading_number = 10 ** fractional_part
    return int(leading_number)

